/**
* Load persisted Connect Pro settings from Obsidian plugin data storage.
* Defaults:
* - connect_on_startup: true
* @returns {Promise<{ connect_on_startup: boolean }>}
*/
async load_connect_pro_settings() {
if (this._connect_pro_settings_loaded) {
return this.connect_pro_settings || { ...DEFAULT_CONNECT_PRO_SETTINGS };
}
let data = null;
try {
data = await this.loadData();
} catch (_) {
data = null;
}
this.connect_pro_settings = build_connect_pro_settings(data);
this._connect_pro_settings_loaded = true;
return this.connect_pro_settings;
}
/**
* Persist Connect Pro settings without overwriting unknown keys saved by future versions.
*/
async save_connect_pro_settings() {
const settings = this.connect_pro_settings || { ...DEFAULT_CONNECT_PRO_SETTINGS };
let existing = null;
try {
existing = await this.loadData();
} catch (_) {
existing = null;
}
const existing_obj = existing && typeof existing === "object" ? existing : {};
const merged = { ...existing_obj, ...settings };
try {
await this.saveData(merged);
} catch (_) {
}
}
/**
* @returns {boolean}
*/
get_connect_on_startup() {
const value = this.connect_pro_settings?.connect_on_startup;
if (typeof value === "boolean") {
return value;
}
return true;
}
/**
* @param {boolean} value
*/
async set_connect_on_startup(value) {
await this.load_connect_pro_settings();
if (!this.connect_pro_settings) {
this.connect_pro_settings = { ...DEFAULT_CONNECT_PRO_SETTINGS };
}
this.connect_pro_settings.connect_on_startup = value === true;
await this.save_connect_pro_settings();
this.refresh_connect_pro_ui();
}
